1071: Http::FilterTrailersStatus Filter::decodeTrailers(Http::RequestTrailerMap& trailers) {
1072:   ENVOY_STREAM_LOG(debug, "router decoding trailers:\n{}", *callbacks_, trailers);
1073: 
1074:   if (shadow_headers_) {
1075:     shadow_trailers_ = Http::createHeaderMap<Http::RequestTrailerMapImpl>(trailers);
1076:   }
1077: 
1078:   // upstream_requests_.size() cannot be > 1 because that only happens when a per
1079:   // try timeout occurs with hedge_on_per_try_timeout enabled but the per
1080:   // try timeout timer is not started until onRequestComplete(). It could be zero
1081:   // if the first request attempt has already failed and a retry is waiting for
1082:   // a backoff timer.
1083:   ASSERT(upstream_requests_.size() <= 1);
1084:   downstream_trailers_ = &trailers;
1085:   if (!upstream_requests_.empty()) {
1086:     upstream_requests_.front()->acceptTrailersFromRouter(trailers);
1087:   }
1088:   for (auto* shadow_stream : shadow_streams_) {
1089:     shadow_stream->removeDestructorCallback();
1090:     shadow_stream->removeWatermarkCallbacks();
1091:     shadow_stream->captureAndSendTrailers(
1092:         Http::createHeaderMap<Http::RequestTrailerMapImpl>(*shadow_trailers_));
1093:   }
1094:   shadow_streams_.clear();
1095: 
1096:   onRequestComplete();
1097:   return Http::FilterTrailersStatus::StopIteration;
1098: }
